def get_quote(self, symbol):
    import time as _t
    hit = self._quote_cache.get(symbol)
    if hit and _t.time() - hit[0] < self._quote_ttl:
        return hit[1]
    raw = {"symbol": symbol}
    # 1) secdef (trần/sàn/tham chiếu) — tĩnh, cache cả phiên
    sd = self._secdef_cache.get(symbol)
    if sd is None:
        try:
            sd = self.client.secdef(symbol) or {}
            if isinstance(sd, list):
                sd = sd[0] if sd else {}
            self._secdef_cache[symbol] = sd
        except Exception as e:
            sd = {}
            print(f"[dnse] ⚠ secdef {symbol} lỗi: {e}")
    raw.update(sd if isinstance(sd, dict) else {})
    # 2) khớp lệnh mới nhất (giá + KL lũy kế)
    try:
        tr = self.client.latest_trade(symbol)
        if isinstance(tr, list):
            tr = tr[0] if tr else {}
        if isinstance(tr, dict):
            raw.update(tr)
    except Exception as e:
        print(f"[dnse] ⚠ trade {symbol} lỗi: {e}")
    # 3) top giá chờ — chấp nhận cả dạng phẳng lẫn dạng mảng bids/offers
    try:
        qt = self.client.latest_quote(symbol)
        if isinstance(qt, list):
            qt = qt[0] if qt else {}
        if isinstance(qt, dict):
            for side_key, flat in (("bids", "bidPrice1"), ("bidprices", "bidPrice1"),
                                   ("offers", "offerPrice1"), ("asks", "offerPrice1"),
                                   ("offerprices", "offerPrice1")):
                arr = qget(qt, side_key)
                if isinstance(arr, list) and arr:
                    top = arr[0]
                    raw.setdefault(flat, qget(top, "price", "p") if
                                   isinstance(top, dict) else top)
            raw.update({k: v for k, v in qt.items() if not isinstance(v, (list, dict))})
    except Exception as e:
        print(f"[dnse] ⚠ quote {symbol} lỗi: {e}")
    q = Quote(raw)
    if not q.ok():
        self._log_raw("quote_unmapped", raw)
    self._quote_cache[symbol] = (_t.time(), q)
    return q

